import {ServiceOptions} from 'jibo-service-framework';

export interface SSMService {
    init(callback: (err?: Error) => void): void;
}

export interface SSMServiceClass {
    instance: SSMService;
    new(options: ServiceOptions, rootDir: string): SSMService;
}

export function instantiateService(
    ServiceClass: SSMServiceClass,
    options?: ServiceOptions,
    rootDir?: string,
) {
    return new ServiceClass(options, rootDir);
}
