//this uses a slimed down version of three.js
//(global as any).miniThree = true;
(global as any).realThree = true;
import XMLHttpRequest from 'xmlhttprequest';
(global as any).XMLHttpRequest = XMLHttpRequest;
import {
    NotificationsDispatcher,
    RegistryClient,
    RegistrationRecord,
    SystemManagerClient,
} from 'jibo-service-framework';
import {PromiseUtils as Async} from 'jibo-cai-utils';
import ExpressionService from '../../services/expression/ExpressionService';
import {instantiateService} from '../../SSMService';
import WebSocket = require('ws');
import {Log} from 'jibo-log';

(global as any).WebSocket = WebSocket;
Log.processName = 'exp';
import parentLog from '../../services/log';
const log: Log = parentLog.createChild('Exp');

async function main() {
    RegistryClient.createInstance('127.0.0.1', 8181);
    const record = await Async.promisify<RegistrationRecord>(
        cb => RegistryClient.instance.getRecordByName('system-manager', cb)
    );
    SystemManagerClient.createInstance('127.0.0.1', record.port);
    const mode = await Async.promisify<string>(cb => SystemManagerClient.instance.getMode(cb));
    const configPath = `/usr/local/etc/jibo-ssm/jibo-ssm-${mode}.json`;
    const config = require(configPath);
    if(config.logging) {
        try {
            await Log.loadConfig(config.logging);
        }
        catch (err) {
            console.error('Error loading config', err);
        }
    }
    NotificationsDispatcher.instance.init(async err => {
        if (err) {
            return log.error('Error initializing NotificationsDispatcher', err);
        }
        try {
            await Log.handleLogLevelNotifications(
                NotificationsDispatcher.instance,
            );
        }
        catch(err) {
            log.error('Failed to set up log level notification handler', err);
        }
    });
    (global as any).expression = instantiateService(ExpressionService, {
        port: 10015,
    }, __dirname);
    try {
        let pid:number = process.pid;
        if(process.argv.indexOf('--pid') >= 0) {
            //the system manager is expecting the parent process to report its startup
            //so we need to use the parent pid
            pid = parseInt(process.argv[3]);
        }
        await Async.promisify<void>(cb => ExpressionService.instance.init(cb));
        const sem = require('node-semaphore');
        const s = sem.Semaphore('/jibo-startup-' + process.pid + '.event');
        s.post();
        log.info('Finished initialization reporting pid', pid);
    }
    catch(e) {
        log.error('Could not initialize expression service', e);
    }
}

main();
