import {ServiceRemoteObject, RemoteService} from 'jibo-service-framework';
import {PlayStatus} from 'jibo-common-types';
import WebSocket = require('ws');
import {Animate, Time, Clock} from 'animation-utilities';
import AnimationBuilder = Animate.AnimationBuilder;
import AnimInstance = Animate.AnimationInstance;
import {DOFArbiter} from 'jibo-dof-arbiter';

export default class AnimationInstance extends ServiceRemoteObject {

    static STARTED:string = 'STARTED';
    static STOPPED:string = 'STOPPED';
    static EVENT:string = 'EVENT';
    static CANCELLED:string = 'CANCELLED';
    static REJECTED: string = 'REJECTED';

    public timeFinishedInteraction:Time = null;
    public timeCacheDeleted:Time = null;

    private instance:AnimInstance;
    private wasRejected:boolean = false;

    constructor(options:{base:RemoteService, owner:WebSocket},
        private builder:AnimationBuilder,
        id:string,
        private dofArbiter:DOFArbiter,
        private cacheName:string) {
        super(options);
        this.onBuilderStopped = this.onBuilderStopped.bind(this);
        this.onEvent = this.onEvent.bind(this);
        this.onCancelled = this.onCancelled.bind(this);
        this.onStarted = this.onStarted.bind(this);
    }

    public async play(requestor:string = 'Behavior'):Promise<PlayStatus> {
        this.addBuilderListeners();
        this.instance = this.dofArbiter.playAnimation(this.builder, requestor);
        this.removeBuilderListeners();
        if(this.instance) {
            return PlayStatus.OK;
        }
        else {
            this.wasRejected = true;
            // delay the REJECTED event to the 'check' phase so that it comes after the play() method reply on the wire
            setImmediate(() => {
                this.emit(AnimationInstance.EVENT, AnimationInstance.REJECTED);
            });
            return PlayStatus.REJECTED;
        }
    }

    public async stop():Promise<void> {
        if(this.instance) {
            this.instance.stop();
        }
    }

    public async pause():Promise<void> {
        if(this.instance) {
            (this.instance as any).setPaused(true);
        }
    }

    public async resume():Promise<void> {
        if(this.instance) {
            (this.instance as any).setPaused(false);
        }
    }

    public destroy() {
        this.remove();
    }

    public notifyCacheDeleted(cacheName:string){
        if(cacheName === this.cacheName){
            this.timeCacheDeleted = Clock.currentTime();
        }
    }


    private addBuilderListeners() {
        this.builder.on(AnimationInstance.STOPPED, this.onBuilderStopped);
        this.builder.on(AnimationInstance.EVENT, this.onEvent);
        this.builder.on(AnimationInstance.CANCELLED, this.onCancelled);
        this.builder.on(AnimationInstance.STARTED, this.onStarted);
    }

    private removeBuilderListeners() {
        this.builder.off(AnimationInstance.STOPPED, this.onBuilderStopped);
        this.builder.off(AnimationInstance.EVENT, this.onEvent);
        this.builder.off(AnimationInstance.CANCELLED, this.onCancelled);
        this.builder.off(AnimationInstance.STARTED, this.onStarted);
    }

    private onBuilderStopped(event, instance:AnimInstance, payload:{interrupted:boolean}) {
        this.emit(AnimationInstance.EVENT, AnimationInstance.STOPPED);
        this.instance = undefined;
        this.timeFinishedInteraction = Clock.currentTime(); //we will emit no more events, and have nothing left to do
    }

    private onCancelled(event, instance:AnimInstance, payload) {
        if(!this.wasRejected) {
            // only emit the CANCELLED event if the animation was NOT rejected by the dof arbiter
            this.emit(AnimationInstance.EVENT, AnimationInstance.CANCELLED);
        }
        this.instance = undefined;
        this.timeFinishedInteraction = Clock.currentTime(); //we will emit no more events, and have nothing left to do
    }

    private onEvent(event, instance:AnimInstance, payload) {
        this.emit(AnimationInstance.EVENT, payload.eventName, payload.payload);
    }

    private onStarted(event, instance:AnimInstance, payload) {
        this.emit(AnimationInstance.EVENT, AnimationInstance.STARTED);
    }
}
