import {DOFArbiter} from 'jibo-dof-arbiter';
import {Animate} from 'animation-utilities';
import {PromiseUtils as Async} from 'jibo-cai-utils';
import {RegistrationRecord, RegistryClient} from 'jibo-service-framework';
import * as services from 'jibo-service-clients/lib/expression-service-clients';

/**
 * This is a jibo mock object for the attention system. It provides the minimal
 * interface that is used by the attention system.
 */
export default class Jibo {
    public lps:typeof services.lps;

    constructor(public robotInfo, public animate:typeof Animate, public dofArbiter:DOFArbiter) {

    }

    public async init():Promise<void> {
        this.lps = services.lps;
        const record = await Async.promisify<RegistrationRecord>(
            cb => RegistryClient.instance.getRecordByName('lps', cb)
        );
        await Async.promisify<void>(cb => {
            services.init({}, [record], cb);
        });
    }
}
