import {RemoteService, ServiceOptions, WebSocket, RejectionHandler} from 'jibo-service-framework';
import {RegistryClient, RegistrationRecord} from 'jibo-service-framework';
import {PromiseUtils as Async} from 'jibo-cai-utils';
import {body, LEDOutput, JiboConfig} from "animation-utilities";
import {TimelineBuilder, RobotInfo, animate as anim} from "animation-utilities";
import {Animate} from "animation-utilities";
import {slog} from "animation-utilities";
import {default as Expression, BuilderCache} from './Expression';
import {DOFArbiter, PriorityConfig} from 'jibo-dof-arbiter';
import {AttentionManager} from 'jibo-attention-manager';
import Jibo from './attention/Jibo';
import {AttentionMode} from 'jibo-common-types';
import log from './log';
import {SSMService} from '../../SSMService';


export default class ExpressionService extends RemoteService implements SSMService {

    private static _instance:ExpressionService;

    public animate:typeof Animate;
    public dofArbiter:DOFArbiter;
    public expression:Expression;
    public bodyOutput:any;
    public robotInfo:any;
    public timeline:any;
    public attention:AttentionManager;

    public static get instance():ExpressionService {
        return ExpressionService._instance;
    }

    constructor(options:ServiceOptions, staticDir:string) {
        super('expression', options, staticDir);
        if (ExpressionService._instance) {
            throw new Error('Cannot instantiate ExpressionService more than once');
        }
        ExpressionService._instance = this;
        log.info('Instantiated');
    }

    init(callback:(err?) => void) {
        super.init((err) => {
            if(err) {
                return callback(err);
            }
            this._init()
                .then(res => callback())
                .catch(callback);
        });
    }

    protected onClose(client:WebSocket):void {
        super.onClose(client);
        this.expression.setAttentionMode(AttentionMode.OFF);
        if (this.expression.isPerformingShutdownPose()) {
            this.expression.centerRobot({ requestor: 'Test', centerGlobally: true }).then(() => {
                this.emit('system-reset');
            });
        } else {
            this.emit('system-reset');
        }
        this.expression.cache = new BuilderCache();
    }

    private async _init():Promise<void> {
        await this.initAnimUtils();
        await this.initDOFArbiter();
        await this.initAttention();
        this.expression = new Expression(
            this,
            this.animate,
            this.dofArbiter,
            this.attention,
            this.timeline,
            this.robotInfo
        );
    }

    private async initAnimUtils():Promise<void> {
        const auLog = log.createChild('AU');
        slog.wrapLog(auLog.debug.bind(auLog), auLog.info.bind(auLog), auLog.warn.bind(auLog), auLog.error.bind(auLog));
        const config = new JiboConfig();
        this.robotInfo = await Async.promisify<any>(
            cb => RobotInfo.createInfo(config, cb),
            false
        );
        this.timeline = await Async.promisify<any>(
            cb => TimelineBuilder.createTimeline(this.robotInfo, cb),
            false
        );
        this.animate = anim.createAnimationUtilities();
        (this.animate as any).init(this.timeline, this.robotInfo);
        return this.connectToBody();
    }

    private async connectToBody():Promise<void> {
        try {
            const record = await Async.promisify<RegistrationRecord>(
                cb => RegistryClient.instance.getRecordByName('body', cb)
            );
            const uri:string = "ws:" + record.host + ":" + record.port;
            const clock = this.timeline.getClock();
            this.bodyOutput = new body.BodyPosVelOutput(clock, this.robotInfo, uri, true, 33);
            const ledOutput = new LEDOutput(clock, this.robotInfo, uri, true, 33);
            this.timeline.addOutput(this.bodyOutput);
            this.timeline.addOutput(ledOutput);

            // pass module types through to the singleton instance
            (this.animate as any).MODALITY_NAME = (anim as any).MODALITY_NAME;
            (this.animate as any).trajectory = (anim as any).trajectory;
            (this.animate as any).AnimationEventType = (anim as any).AnimationEventType;
            (this.animate as any).LookatEventType = (anim as any).LookatEventType;
            this.lazyInitCheck = null;
        }
        catch (err) {
            log.warn('Issue connecting to body.  Will try again when service is requested', err);
            if (!this.lazyInitCheck) {
                this.lazyInitCheck = (callback: RejectionHandler) => {
                    if (!this.bodyOutput) {
                        this.connectToBody().then(() => callback(null), err => callback(err));
                    }
                    else {
                        callback(null);
                    }
                };
            }
        }
    }

    private async initDOFArbiter():Promise<void> {
        const config:PriorityConfig = {
    		priorityForUnknownLabels: 5,
    		priorityForDirectUsers: 10,
            priorityEntries: [
    			{owner: 'LowTest', priority: 1},
                {owner: 'Cleanup', priority: 2},
    			{owner: 'Attention', priority: 3},
    			{owner: 'Behavior', priority: 5},
    			{owner: 'EmbodiedSpeech', priority: 5},
    			{owner: 'EmbodiedListen', priority: 7},
    			{owner: 'AttentionCommand', priority: 7},
    			{owner: 'BargeIn', priority: 8},
    			{owner: 'Test', priority: 9}
    		]
    	};
        this.dofArbiter = new DOFArbiter();
        this.dofArbiter.init(this.animate, config);
    }

    private async initAttention():Promise<void> {
        //create the jibo mock object
        const jeebo:Jibo = new Jibo(this.robotInfo, this.animate, this.dofArbiter);
        await jeebo.init();
        this.attention = new AttentionManager(jeebo);
    }
}
