import {ServiceRemoteObject, RemoteService} from 'jibo-service-framework';
import WebSocket = require('ws');
import {Time, Clock} from 'animation-utilities';
import parentLog from './log';

const log = parentLog.createChild('Attention');

export default class AttentionHandle extends ServiceRemoteObject {

    public timeFinishedInteraction:Time = null;

    constructor(options:{base:RemoteService, owner:WebSocket},
        private handle:any) {
        super(options);
    }

    public async release():Promise<boolean> {
        let result = false;
        if(this.handle) {
            result = this.handle.release();
        }else{
            log.warn("release called on already-done AttentionHandle!");
        }

        this.handle = undefined;

        this.timeFinishedInteraction = Clock.currentTime();

        return result;
    }

    public destroy() {
        if(this.handle) {
            log.debug('DESTROYING ATTENTION HANDLE');
            this.handle.release();
            this.handle = undefined;
        }
        this.remove();
    }
}
